import json
from kafka import KafkaConsumer, KafkaProducer

class KafkaParser:
    def __init__(self, input_topic, output_topic, kafka_servers):
        self.consumer = KafkaConsumer(input_topic, bootstrap_servers=kafka_servers)
        self.producer = KafkaProducer(bootstrap_servers=kafka_servers)

    def parse_message(self, message):
        try:
            record = json.loads(message.value)
            # Assuming the record is a dictionary and we want to count the number of keys
            count = len(record)
            return count
        except json.JSONDecodeError:
            return 0  # Return 0 for invalid JSON
        except Exception as e:
            print(f"Error processing message: {e}")
            return 0

    def process_messages(self):
        for message in self.consumer:
            count = self.parse_message(message)
            self.producer.send(output_topic, value=str(count).encode('utf-8'))

def solve(input_topic, output_topic, kafka_servers):
    parser = KafkaParser(input_topic, output_topic, kafka_servers)
    parser.process_messages()
